import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { Link } from 'react-router-dom';
import { useSearchParams } from 'react-router-dom';
import ProductCard from '../components/ProductCard';
import useAuth from '../context/useAuth';
import useLanguage from '../context/useLanguage';
import useProducts from '../context/useProducts';
import useDocumentTitle from '../hooks/useDocumentTitle';

const ALLOWED_SORTS = ['featured', 'price-asc', 'price-desc', 'name-asc', 'name-desc'];

// Generated by GitHub Copilot
/**
 * Normalizes text for accent-insensitive and case-insensitive searching.
 * @param {string} value
 * @returns {string}
 */
function normalizeForSearch(value) {
  return String(value ?? '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');
}

// Generated by GitHub Copilot
/**
 * Returns true when a keyboard event target is an element meant for text input.
 * @param {EventTarget | null} target
 * @returns {boolean}
 */
function isTypingTarget(target) {
  if (!(target instanceof HTMLElement)) {
    return false;
  }

  const tag = target.tagName;
  return target.isContentEditable || tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT';
}

/**
 * Reads and sanitizes list params from URL to keep UI shareable and stable.
 * @param {import('react-router-dom').URLSearchParamsInit} searchParams
 * @param {Array<string>} categories
 */
function parseListParams(searchParams, categories) {
  const categoryParam = searchParams.get('categoria') || 'Todos';
  const category = categories.includes(categoryParam) ? categoryParam : 'Todos';

  const sortParam = searchParams.get('orden') || 'featured';
  const sortBy = ALLOWED_SORTS.includes(sortParam) ? sortParam : 'featured';

  const pageParam = Number.parseInt(searchParams.get('pagina') || '1', 10);
  const currentPage = Number.isNaN(pageParam) || pageParam < 1 ? 1 : pageParam;

  const rawSearch = searchParams.get('q') || '';
  const search = rawSearch.slice(0, 100);

  return { category, sortBy, currentPage, search };
}

/**
 * Home page showing the product grid with category filter.
 * Filters are implemented client-side for performance.
 */
export default function Home() {
  const { user } = useAuth();
  const { products, categories } = useProducts();
  const { t, translateCategory } = useLanguage();
  // WCAG 2.4.2: descriptive page title announced by screen readers on navigation.
  useDocumentTitle(t('home.title'));

  const isAdmin = user?.role === 'admin';
  const [searchParams, setSearchParams] = useSearchParams();
  const paramsSnapshot = searchParams.toString();
  const [activeCategory, setActiveCategory] = useState(() => parseListParams(searchParams, categories).category);
  const [search, setSearch] = useState(() => parseListParams(searchParams, categories).search);
  const [debouncedSearch, setDebouncedSearch] = useState(() => parseListParams(searchParams, categories).search);
  const [sortBy, setSortBy] = useState(() => parseListParams(searchParams, categories).sortBy);
  const [currentPage, setCurrentPage] = useState(() => parseListParams(searchParams, categories).currentPage);
  const searchInputRef = useRef(null);
  const noResultsHeadingRef = useRef(null);
  const pageSize = 8;
  const effectiveCategory = categories.includes(activeCategory) ? activeCategory : 'Todos';

  useEffect(() => {
    const timeoutId = setTimeout(() => {
      setDebouncedSearch(search);
    }, 250);

    return () => clearTimeout(timeoutId);
  }, [search]);

  useEffect(() => {
    /**
     * Focuses search input with slash shortcut while preserving native typing behavior.
     * @param {KeyboardEvent} event
     */
    const handleSlashShortcut = (event) => {
      if (event.key !== '/' || event.altKey || event.ctrlKey || event.metaKey) {
        return;
      }
      if (isTypingTarget(event.target)) {
        return;
      }

      event.preventDefault();
      searchInputRef.current?.focus();
    };

    window.addEventListener('keydown', handleSlashShortcut);
    return () => {
      window.removeEventListener('keydown', handleSlashShortcut);
    };
  }, []);

  const filteredByCategory = useMemo(
    () => (effectiveCategory === 'Todos'
      ? products
      : products.filter((p) => p.category === effectiveCategory)),
    [effectiveCategory, products]
  );

  const filtered = useMemo(() => {
    const normalizedSearch = normalizeForSearch(debouncedSearch.trim());
    if (!normalizedSearch) {
      return filteredByCategory;
    }

    return filteredByCategory.filter((product) => (
      normalizeForSearch(product.name).includes(normalizedSearch)
      || normalizeForSearch(product.description).includes(normalizedSearch)
      || normalizeForSearch(product.category).includes(normalizedSearch)
    ));
  }, [debouncedSearch, filteredByCategory]);

  const sortedProducts = useMemo(() => [...filtered].sort((a, b) => {
    if (sortBy === 'price-asc') {
      return a.price - b.price;
    }
    if (sortBy === 'price-desc') {
      return b.price - a.price;
    }
    if (sortBy === 'name-asc') {
      return a.name.localeCompare(b.name);
    }
    if (sortBy === 'name-desc') {
      return b.name.localeCompare(a.name);
    }
    return 0;
  }), [filtered, sortBy]);

  const totalPages = Math.max(1, Math.ceil(sortedProducts.length / pageSize));
  const safeCurrentPage = Math.min(currentPage, totalPages);
  const paginatedProducts = sortedProducts.slice(
    (safeCurrentPage - 1) * pageSize,
    safeCurrentPage * pageSize
  );

  useEffect(() => {
    const params = new URLSearchParams();
    if (effectiveCategory !== 'Todos') {
      params.set('categoria', effectiveCategory);
    }
    if (sortBy !== 'featured') {
      params.set('orden', sortBy);
    }
    if (search.trim()) {
      params.set('q', search.trim());
    }
    if (safeCurrentPage > 1) {
      params.set('pagina', String(safeCurrentPage));
    }

    const nextParams = params.toString();
    const currentParams = searchParams.toString();
    if (nextParams !== currentParams) {
      setSearchParams(params, { replace: true });
    }
  }, [effectiveCategory, paramsSnapshot, safeCurrentPage, search, setSearchParams, sortBy]);

  useEffect(() => {
    const parsed = parseListParams(searchParams, categories);
    setActiveCategory((prev) => (prev === parsed.category ? prev : parsed.category));
    setSortBy((prev) => (prev === parsed.sortBy ? prev : parsed.sortBy));
    setCurrentPage((prev) => (prev === parsed.currentPage ? prev : parsed.currentPage));
    setSearch((prev) => (prev === parsed.search ? prev : parsed.search));
    setDebouncedSearch((prev) => (prev === parsed.search ? prev : parsed.search));
  }, [categories, paramsSnapshot]);

  // Generated by GitHub Copilot
  const clearFilters = useCallback(() => {
    setActiveCategory('Todos');
    setSearch('');
    setSortBy('featured');
    setCurrentPage(1);
    searchInputRef.current?.focus();
  }, []);

  const clearSearch = useCallback(() => {
    setSearch('');
    setCurrentPage(1);
  }, []);

  // Generated by GitHub Copilot
  // Stable callbacks prevent per-render allocations inside the category button list.
  const handleCategoryChange = useCallback((cat) => {
    setActiveCategory(cat);
    setCurrentPage(1);
  }, []);

  const handleSortChange = useCallback((e) => {
    setSortBy(e.target.value);
    setCurrentPage(1);
  }, []);

  const handleSearchChange = useCallback((e) => {
    setSearch(e.target.value);
    setCurrentPage(1);
  }, []);

  const handleSearchKeyDown = useCallback((event) => {
    if (event.key === 'Escape' && search.trim()) {
      event.preventDefault();
      clearSearch();
    }
  }, [clearSearch, search]);

  const handleCategoryButtonClick = useCallback((event) => {
    const nextCategory = event.currentTarget.dataset.category;
    if (!nextCategory) {
      return;
    }

    handleCategoryChange(nextCategory);
  }, [handleCategoryChange]);

  const hasActiveFilters = effectiveCategory !== 'Todos' || debouncedSearch.trim() !== '' || sortBy !== 'featured';

  useEffect(() => {
    if (sortedProducts.length === 0 && hasActiveFilters) {
      noResultsHeadingRef.current?.focus();
    }
  }, [hasActiveFilters, sortedProducts.length]);

  // Generated by GitHub Copilot
  // Pagination: functional updater form avoids stale closure; useCallback keeps reference stable.
  const handlePrevPage = useCallback(() => {
    setCurrentPage((prev) => Math.max(1, prev - 1));
  }, []);

  const handleNextPage = useCallback(() => {
    setCurrentPage((prev) => Math.min(totalPages, prev + 1));
  }, [totalPages]);

  const resultsSummaryText = useMemo(() => t('common.resultsCount', {
    count: sortedProducts.length,
    suffix: sortedProducts.length !== 1 ? 's' : '',
  }), [sortedProducts.length, t]);

  const pageSummaryText = useMemo(
    () => `${t('common.page')} ${safeCurrentPage} ${t('common.of')} ${totalPages}`,
    [safeCurrentPage, t, totalPages]
  );

  return (
    <main className="max-w-6xl mx-auto px-4 py-8">
      <h1 className="text-3xl font-bold text-gray-900 mb-2">{t('home.title')}</h1>
      <p className="text-gray-500 mb-6">{t('home.subtitle')}</p>

      {isAdmin && (
        <section className="mb-8 rounded-2xl border border-indigo-200 bg-indigo-50/40 p-4" aria-label={t('home.adminAccess')}>
          <h2 className="text-lg font-semibold text-indigo-900 mb-1">{t('home.catalogManagement')}</h2>
          <p className="text-sm text-indigo-800 mb-3">{t('home.catalogManagementBody')}</p>
          <Link
            to="/admin/productos"
            className="inline-block rounded-lg bg-indigo-600 px-4 py-2 text-sm font-semibold text-white transition hover:bg-indigo-700 focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600"
          >
            {t('home.goToAdminPanel')}
          </Link>
        </section>
      )}

      <section className="mb-6 grid grid-cols-1 md:grid-cols-3 gap-3" aria-label={t('home.searchAndSortControls')}>
        <label className="md:col-span-2 relative">
          <span className="sr-only">{t('home.searchProducts')}</span>
          <input
            ref={searchInputRef}
            type="search"
            value={search}
            onChange={handleSearchChange}
            onKeyDown={handleSearchKeyDown}
            placeholder={t('home.searchPlaceholder')}
            aria-describedby="home-search-shortcut"
            className="w-full rounded-xl border border-gray-300 bg-white px-4 py-2.5 pr-24 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
          />
          {search.trim() && (
            <button
              type="button"
              onClick={clearSearch}
              className="absolute right-2 top-1/2 -translate-y-1/2 rounded-lg border border-gray-300 bg-white px-2.5 py-1 text-xs font-medium text-gray-700 transition hover:bg-gray-50 focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600"
              aria-label={t('common.clearSearch')}
            >
              {t('common.clearSearch')}
            </button>
          )}
          <p id="home-search-shortcut" className="mt-1 text-xs text-gray-500">
            {t('home.searchShortcutHint')}
          </p>
        </label>
        <label>
          <span className="sr-only">{t('home.sortProducts')}</span>
          <select
            value={sortBy}
            onChange={handleSortChange}
            className="w-full rounded-xl border border-gray-300 bg-white px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
          >
            <option value="featured">{t('home.featured')}</option>
            <option value="price-asc">{t('home.priceLowHigh')}</option>
            <option value="price-desc">{t('home.priceHighLow')}</option>
            <option value="name-asc">{t('home.nameAsc')}</option>
            <option value="name-desc">{t('home.nameDesc')}</option>
          </select>
        </label>
      </section>

      <p className="text-sm text-gray-500 mb-6">
        {resultsSummaryText}
        {' · '}
        {pageSummaryText}
      </p>

      <p className="sr-only" role="status" aria-live="polite" aria-atomic="true">
        {resultsSummaryText}
        {' · '}
        {pageSummaryText}
        {' · '}
        {t('home.filterByCategory')}: {translateCategory(effectiveCategory)}
      </p>

      <div className="mb-6 flex justify-end">
        {hasActiveFilters && (
          <button
            type="button"
            onClick={clearFilters}
            className="rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm font-medium text-gray-700 transition hover:bg-gray-50 focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600"
          >
            {t('common.clearFilters')}
          </button>
        )}
      </div>

      {/* Category filter */}
      <div
        className="flex flex-wrap gap-2 mb-8"
        role="group"
        aria-label={t('home.filterByCategory')}
      >
        {categories.map((cat) => (
          <button
            key={cat}
            type="button"
            onClick={handleCategoryButtonClick}
            data-category={cat}
            className={`px-4 py-1.5 rounded-full text-sm font-medium transition focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600 ${
              effectiveCategory === cat
                ? 'bg-indigo-600 text-white'
                : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
            }`}
            aria-pressed={effectiveCategory === cat}
          >
            {translateCategory(cat)}
          </button>
        ))}
      </div>

      {/* Product grid */}
      <section
        aria-label={t('home.productList')}
        className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6"
      >
        {paginatedProducts.map((product) => (
          <ProductCard
            key={product.id}
            product={product}
            searchQuery={debouncedSearch}
          />
        ))}
      </section>

      {sortedProducts.length > pageSize && (
        <nav className="mt-8 flex items-center justify-center gap-3" aria-label={t('home.paginationProducts')}>
          <button
            type="button"
            onClick={handlePrevPage}
            disabled={safeCurrentPage === 1}
            className="rounded-lg border border-gray-300 bg-white px-4 py-2 text-sm font-medium text-gray-700 transition hover:bg-gray-50 disabled:cursor-not-allowed disabled:opacity-50"
          >
            {t('common.previous')}
          </button>
          <span className="text-sm text-gray-600" aria-label={t('home.pageXofY', { current: safeCurrentPage, total: totalPages })}>{safeCurrentPage} / {totalPages}</span>
          <button
            type="button"
            onClick={handleNextPage}
            disabled={safeCurrentPage === totalPages}
            className="rounded-lg border border-gray-300 bg-white px-4 py-2 text-sm font-medium text-gray-700 transition hover:bg-gray-50 disabled:cursor-not-allowed disabled:opacity-50"
          >
            {t('common.next')}
          </button>
        </nav>
      )}

      {sortedProducts.length === 0 && (
        <div className="mt-8 rounded-2xl border border-dashed border-gray-300 bg-white px-6 py-10 text-center">
          <p ref={noResultsHeadingRef} className="text-lg font-semibold text-gray-800" tabIndex={-1}>{t('common.noResults')}</p>
          <p className="text-sm text-gray-500 mt-1">{t('common.tryAnotherSearch')}</p>
        </div>
      )}
    </main>
  );
}
